title: $:/core/modules/commands/inspect/handlers/filesystem.js
type: application/javascript
module-type: library

MCP tool handlers for filesystem and build operations.

\*/

"use strict";

var fs = require("fs"),
	path = require("path");

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

// Change log: accumulates $tw.wiki changes between reload_tiddlers calls
var changeLog = {};
var changeLogActive = false;

function startChangeLog() {
	if(changeLogActive) {
		return;
	}
	changeLogActive = true;
	$tw.wiki.addEventListener("change", function(changes) {
		var titles = Object.keys(changes);
		for(var i = 0; i < titles.length; i++) {
			var title = titles[i];
			if(title.indexOf("$:/") === 0) {
				continue;
			}
			if(changes[title].deleted) {
				changeLog[title] = "deleted";
			} else if(changeLog[title] === undefined) {
				changeLog[title] = "added";
			} else {
				changeLog[title] = "updated";
			}
		}
	});
}

module.exports = {
	"reload_tiddlers": function(args) {
		var scope = (args && args.scope) || "tiddlers";
		var messages = [];

		// Reload edition tiddlers
		if(scope === "tiddlers" || scope === "all") {
			if(!$tw.boot.wikiTiddlersPath) {
				return shared.errorResult("No wiki tiddlers path available. Cannot reload from filesystem.");
			}
			var resolvedWikiPath = $tw.boot.wikiTiddlersPath;
			var wikiInfo = $tw.boot.wikiInfo || {};
			var config = wikiInfo.config || {};
			var countBefore = $tw.wiki.allTitles().length;
			var added = 0, updated = 0, skippedSystem = 0, unchanged = 0;
			var diskTiddlers = Object.create(null);
			var diskFileInfo = Object.create(null);
			$tw.utils.each($tw.loadTiddlersFromPath(resolvedWikiPath), function(tiddlerFile) {
				$tw.utils.each(tiddlerFile.tiddlers, function(tiddlerFields) {
					var title = tiddlerFields.title;
					if(!title) return;
					diskTiddlers[title] = tiddlerFields;
					if(tiddlerFile.filepath) {
						diskFileInfo[title] = {
							filepath: tiddlerFile.filepath,
							type: tiddlerFile.type,
							hasMetaFile: tiddlerFile.hasMetaFile,
							isEditableFile: config["retain-original-tiddler-path"] || tiddlerFile.isEditableFile || tiddlerFile.filepath.indexOf($tw.boot.wikiTiddlersPath) !== 0
						};
					}
				});
			});
			for(var title in diskTiddlers) {
				if(title.indexOf("$:/") === 0) {
					skippedSystem++;
					continue;
				}
				var tiddlerFields = diskTiddlers[title];
				if(diskFileInfo[title]) {
					$tw.boot.files[title] = diskFileInfo[title];
				}
				var existing = $tw.wiki.getTiddler(title);
				if(existing) {
					var changed = false;
					var newTiddler = new $tw.Tiddler(tiddlerFields);
					var existingFields = existing.getFieldStrings();
					var newFields = newTiddler.getFieldStrings();
					if(Object.keys(existingFields).length !== Object.keys(newFields).length) {
						changed = true;
					} else {
						for(var field in newFields) {
							if(existingFields[field] !== newFields[field]) {
								changed = true;
								break;
							}
						}
					}
					if(changed) {
						$tw.wiki.addTiddler(newTiddler);
						updated++;
					} else {
						unchanged++;
					}
				} else {
					$tw.wiki.addTiddler(new $tw.Tiddler(tiddlerFields));
					added++;
				}
			}
			var deleted = 0;
			var allTitles = $tw.wiki.allTitles();
			for(var ti = 0; ti < allTitles.length; ti++) {
				var t = allTitles[ti];
				if($tw.boot.files[t] && $tw.boot.files[t].filepath) {
					var filePath = $tw.boot.files[t].filepath;
					if(filePath.indexOf(resolvedWikiPath) === 0 && !diskTiddlers[t]) {
						$tw.wiki.deleteTiddler(t);
						delete $tw.boot.files[t];
						deleted++;
					}
				}
			}
			var countAfter = $tw.wiki.allTitles().length;
			messages.push("Tiddlers reloaded from: " + resolvedWikiPath);
			messages.push("Before: " + countBefore + ", After: " + countAfter + " (added: " + added + ", updated: " + updated + ", unchanged: " + unchanged + ", skipped-system: " + skippedSystem + ", deleted: " + deleted + ")");
			// Report changes since last reload
			var logTitles = Object.keys(changeLog);
			if(logTitles.length > 0) {
				var logAdded = 0, logUpdated = 0, logDeleted = 0;
				var logLines = [];
				logTitles.sort();
				for(var li = 0; li < logTitles.length; li++) {
					var lt = logTitles[li];
					var action = changeLog[lt];
					if(action === "added") { logAdded++; logLines.push("  + " + lt); }
					else if(action === "updated") { logUpdated++; logLines.push("  ~ " + lt); }
					else if(action === "deleted") { logDeleted++; logLines.push("  - " + lt); }
				}
				messages.push("\nSince last reload: " + logAdded + " added, " + logUpdated + " updated, " + logDeleted + " deleted");
				messages.push(logLines.join("\n"));
				changeLog = {};
			} else if(changeLogActive) {
				messages.push("\nSince last reload: no changes");
			} else {
				messages.push("\nChange tracking started.");
			}
			startChangeLog();
		}

		// Reload shadow tiddlers from plugins
		if(scope === "shadows" || scope === "all") {
			try {
				var shadowsBefore = $tw.wiki.allShadowTitles().length;
				var results = $tw.wiki.readPluginInfo();
				var modified = results.modifiedPlugins || [];
				$tw.wiki.registerPluginTiddlers(null);
				$tw.wiki.unpackPluginTiddlers();
				var shadowsAfter = $tw.wiki.allShadowTitles().length;
				messages.push("\nShadow tiddlers refreshed");
				messages.push("Shadows: " + shadowsBefore + " -> " + shadowsAfter);
				if(modified.length > 0) {
					messages.push("Modified plugins: " + modified.join(", "));
				} else {
					messages.push("No plugin changes detected on disk");
				}
			} catch(e) {
				messages.push("\nShadow reload error: " + e.message);
			}
		}

		return shared.textResult(messages.join("\n"));
	},

	"save_wiki_folder": function(args) {
		var denied = shared.checkWritable("save_wiki_folder");
		if(denied) return denied;
		var checkPathAllowed = shared.getCheckPathAllowed();
		var outputPath = path.resolve(args.path);
		var pathDenied = checkPathAllowed(outputPath);
		if(pathDenied) return pathDenied;
		var tiddlerFilter = args.filter || "[all[tiddlers]]";
		var explodePlugins = (args.explodePlugins === "no") ? "no" : "yes";
		try {
			var commander = new $tw.Commander(
				["--savewikifolder", outputPath, "filter=" + tiddlerFilter, "explodePlugins=" + explodePlugins],
				function(err) {
					if(err) {
						process.stderr.write("[tw-mcp] savewikifolder error: " + err + "\n");
					}
				},
				$tw.wiki
			);
			commander.execute();
			return shared.textResult("Wiki folder saved to: " + outputPath);
		} catch(e) {
			return shared.errorResult("Failed to save wiki folder: " + e.message);
		}
	},

	"upload_file": function(args) {
		var denied = shared.checkWritable("upload_file");
		if(denied) return denied;
		var checkPathAllowed = shared.getCheckPathAllowed();
		var filename = args.filename;
		if(filename.indexOf("/") !== -1 || filename.indexOf("\\") !== -1 || filename.indexOf("..") !== -1) {
			return shared.errorResult("Invalid filename: must not contain path separators or '..'");
		}
		var wikiPath = $tw.boot.wikiPath;
		if(!wikiPath) {
			return shared.errorResult("No wiki path available");
		}
		var filesDir = path.resolve(wikiPath, "files");
		if(args.subfolder) {
			var subfolder = args.subfolder;
			if(subfolder.indexOf("..") !== -1) {
				return shared.errorResult("Invalid subfolder: must not contain '..'");
			}
			filesDir = path.resolve(filesDir, subfolder);
		}
		var targetPath = path.resolve(filesDir, filename);
		var pathDenied = checkPathAllowed(targetPath);
		if(pathDenied) return pathDenied;
		try {
			var buffer = Buffer.from(args.data, "base64");
			$tw.utils.createDirectory(filesDir);
			fs.writeFileSync(targetPath, buffer);
		} catch(e) {
			return shared.errorResult("Failed to write file: " + e.message);
		}
		var title = args.title || filename;
		var canonicalUri = "files/" + (args.subfolder ? args.subfolder + "/" : "") + filename;
		var creationFields = $tw.wiki.getCreationFields();
		var modificationFields = $tw.wiki.getModificationFields();
		var tiddlerFields = {
			title: title,
			type: args.type,
			_canonical_uri: canonicalUri
		};
		if(args.tags) {
			tiddlerFields.tags = args.tags;
		}
		var tiddler = new $tw.Tiddler(creationFields, tiddlerFields, modificationFields);
		$tw.wiki.addTiddler(tiddler);
		try {
			var tiddlerFileInfo = $tw.utils.generateTiddlerFileInfo(tiddler, {
				directory: $tw.boot.wikiTiddlersPath,
				wiki: $tw.wiki,
				fileInfo: {}
			});
			$tw.utils.saveTiddlerToFileSync(tiddler, tiddlerFileInfo);
			$tw.boot.files[title] = tiddlerFileInfo;
		} catch(e) {
			return shared.errorResult("File saved but failed to write .tid tiddler: " + e.message);
		}
		return shared.textResult("File uploaded: " + targetPath + "\nTiddler created: " + tiddlerFileInfo.filepath + " (_canonical_uri: " + canonicalUri + ")");
	},

	"build_wiki": function(args) {
		var denied = shared.checkWritable("build_wiki");
		if(denied) return denied;
		var checkPathAllowed = shared.getCheckPathAllowed();
		var outputFile = path.resolve(args.output);
		var pathDenied = checkPathAllowed(outputFile);
		if(pathDenied) return pathDenied;
		var template = args.template || "$:/core/save/all";
		try {
			var text = $tw.wiki.renderTiddler("text/plain", template);
			$tw.utils.createFileDirectories(outputFile);
			fs.writeFileSync(outputFile, text, "utf8");
			return shared.textResult("Wiki built: " + outputFile);
		} catch(e) {
			return shared.errorResult("Failed to build wiki: " + e.message);
		}
	}
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/html-import.js":{"title":"$:/core/modules/commands/inspect/handlers/html-import.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/html-import.js
type: application/javascript
module-type: library

HTML single-file wiki import handler for MCP server.
Loads tiddlers from an HTML file, analyzes structure, and provides
deferred extraction to disk with FileSystemPaths configuration.

\*/

"use strict";

var fs = require("fs"),
	path = require("path");

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

var TIDDLERS_TO_IGNORE = [
	"$:/boot/boot.css",
	"$:/boot/boot.js",
	"$:/boot/bootprefix.js",
	"$:/core",
	"$:/core-server",
	"$:/library/sjcl.js",
	"$:/temp/info-plugin"
];

var MIN_GROUP_COUNT = 3;

// --- Plugin detection (adapted from savewikifolder.js) ---

function findPluginInLibrary(title) {
	var parts = title.split("/"),
		pluginPath, type, name;
	if(parts[0] === "$:") {
		if(parts[1] === "languages" && parts.length === 3) {
			pluginPath = "languages" + path.sep + parts[2];
			type = parts[1];
			name = parts[2];
		} else if((parts[1] === "plugins" || parts[1] === "themes") && parts.length === 4) {
			pluginPath = parts[1] + path.sep + parts[2] + path.sep + parts[3];
			type = parts[1];
			name = parts[2] + "/" + parts[3];
		}
	}
	if(pluginPath && type && name) {
		pluginPath = path.resolve($tw.boot.bootPath, "..", pluginPath);
		if(fs.existsSync(pluginPath)) {
			return { pluginPath: pluginPath, type: type, name: name };
		}
	}
	return false;
}

// --- Heuristic analysis ---

function analyzeForFileSystemPaths(tiddlers) {
	var tagCounts = {};
	var prefixCounts = {};
	for(var i = 0; i < tiddlers.length; i++) {
		var t = tiddlers[i];
		// Count tags
		var tags = $tw.utils.parseStringArray(t.tags || "");
		for(var ti = 0; ti < tags.length; ti++) {
			var tag = tags[ti];
			if(tag.indexOf("$:/") !== 0) {
				tagCounts[tag] = (tagCounts[tag] || 0) + 1;
			}
		}
		// Count title prefixes (first segment before /)
		var slashIdx = t.title.indexOf("/");
		if(slashIdx > 0) {
			var prefix = t.title.substring(0, slashIdx + 1);
			prefixCounts[prefix] = (prefixCounts[prefix] || 0) + 1;
		}
	}
	// Build proposed rules
	var rules = [];
	var ruleDescriptions = [];
	// System tiddlers
	rules.push("[is[system]removeprefix[$:/]addprefix[_system/]]");
	ruleDescriptions.push("System tiddlers ($:/) → _system/ subfolder");
	// Tags with enough tiddlers
	var sortedTags = Object.keys(tagCounts)
		.filter(function(t) { return tagCounts[t] >= MIN_GROUP_COUNT; })
		.sort(function(a, b) { return tagCounts[b] - tagCounts[a]; });
	for(var si = 0; si < sortedTags.length; si++) {
		var tag = sortedTags[si];
		var folder = tag.toLowerCase().replace(/\s+/g, "-").replace(/[^a-z0-9\-]/g, "_");
		rules.push("[tag[" + tag + "]addprefix[" + folder + "/]]");
		ruleDescriptions.push(tagCounts[tag] + " tiddlers tagged '" + tag + "' → " + folder + "/ subfolder");
	}
	// Title prefixes with enough tiddlers
	var sortedPrefixes = Object.keys(prefixCounts)
		.filter(function(p) { return prefixCounts[p] >= MIN_GROUP_COUNT; })
		.sort(function(a, b) { return prefixCounts[b] - prefixCounts[a]; });
	for(var pi = 0; pi < sortedPrefixes.length; pi++) {
		var prefix = sortedPrefixes[pi];
		rules.push("[prefix[" + prefix + "]]");
		ruleDescriptions.push(prefixCounts[prefix] + " tiddlers with title prefix '" + prefix + "' → keep namespace as subfolder");
	}
	return {
		tagCounts: tagCounts,
		prefixCounts: prefixCounts,
		proposedRules: rules,
		ruleDescriptions: ruleDescriptions,
		proposedText: rules.join("\n")
	};
}

// --- Initialize: load HTML, analyze, import to memory ---

function initialize(htmlFilePath, wiki) {
	var filePath = path.resolve(htmlFilePath);
	if(!fs.existsSync(filePath)) {
		console.error("html-import: File not found: " + filePath);
		return;
	}
	// Re-launch detection: if tiddlers/ has .tid files and FileSystemPaths exists, skip
	if($tw.boot.wikiTiddlersPath && fs.existsSync($tw.boot.wikiTiddlersPath)) {
		var existingFiles = fs.readdirSync($tw.boot.wikiTiddlersPath);
		var hasTidFiles = existingFiles.some(function(f) { return f.endsWith(".tid"); });
		if(hasTidFiles && wiki.tiddlerExists("$:/config/FileSystemPaths")) {
			console.error("html-import: Wiki already has extracted tiddlers and FileSystemPaths — skipping import");
			return;
		}
	}
	// Ensure tiddlers directory exists
	var wikiPath = $tw.boot.wikiPath;
	var tiddlersDir = path.resolve(wikiPath, "tiddlers");
	if(!fs.existsSync(tiddlersDir)) {
		$tw.utils.createDirectory(tiddlersDir);
	}
	if(!$tw.boot.wikiTiddlersPath) {
		$tw.boot.wikiTiddlersPath = tiddlersDir;
	}
	// Ensure tiddlywiki.info exists
	var infoPath = path.resolve(wikiPath, "tiddlywiki.info");
	var wikiInfo;
	if(fs.existsSync(infoPath)) {
		wikiInfo = $tw.utils.parseJSONSafe(fs.readFileSync(infoPath, "utf8"), {});
	} else {
		wikiInfo = {};
	}
	// Load tiddlers from HTML
	var loaded = $tw.loadTiddlersFromPath(filePath);
	// Classify tiddlers
	var contentTiddlers = [];
	var systemTiddlers = [];
	var libraryPlugins = [];
	var customPlugins = [];
	var ignoredCount = 0;
	$tw.utils.each(loaded, function(tiddlerInfo) {
		$tw.utils.each(tiddlerInfo.tiddlers, function(fields) {
			if(!fields.title) return;
			// Skip boot/core tiddlers
			if(TIDDLERS_TO_IGNORE.indexOf(fields.title) !== -1) {
				ignoredCount++;
				return;
			}
			// Check if it's a plugin
			var type = fields.type,
				pluginType = fields["plugin-type"];
			if(type === "application/json" && pluginType) {
				var libraryInfo = findPluginInLibrary(fields.title);
				if(libraryInfo) {
					libraryPlugins.push(libraryInfo);
					return;
				}
				customPlugins.push(fields.title);
				return;
			}
			// System vs content
			if(fields.title.indexOf("$:/") === 0) {
				systemTiddlers.push(fields);
			} else {
				contentTiddlers.push(fields);
			}
		});
	});
	// Update tiddlywiki.info with library plugins
	var infoChanged = false;
	for(var li = 0; li < libraryPlugins.length; li++) {
		var lp = libraryPlugins[li];
		if(!wikiInfo[lp.type]) {
			wikiInfo[lp.type] = [];
		}
		if(wikiInfo[lp.type].indexOf(lp.name) === -1) {
			wikiInfo[lp.type].push(lp.name);
			infoChanged = true;
		}
	}
	if(infoChanged || !fs.existsSync(infoPath)) {
		fs.writeFileSync(infoPath, JSON.stringify(wikiInfo, null, 4), "utf8");
	}
	// Import all content + system tiddlers into memory
	var allTiddlers = contentTiddlers.concat(systemTiddlers);
	for(var ai = 0; ai < allTiddlers.length; ai++) {
		wiki.importTiddler(new $tw.Tiddler(allTiddlers[ai]));
	}
	// Reset syncer baseline so imported tiddlers are not seen as dirty
	if($tw.syncer) {
		$tw.syncer.readTiddlerInfo();
	}
	// Analyze for FileSystemPaths
	var analysis = analyzeForFileSystemPaths(contentTiddlers);
	// Build explanation
	var explanation = [
		"## $:/config/FileSystemPaths",
		"",
		"This TiddlyWiki configuration controls how tiddlers are organized into subdirectories when saved as .tid files.",
		"Each line is a filter expression. Tiddlers are tested against each filter in order — the first match determines the subfolder.",
		"If no filter matches, the tiddler title is used as the filename in the tiddlers/ root.",
		"",
		"Full documentation: https://tiddlywiki.com/#Customising%20Tiddler%20File%20Naming",
		"",
		"## Proposed rules",
		""
	];
	var maxExamples = 10;
	var ruleCount = analysis.ruleDescriptions.length;
	var showCount = Math.min(ruleCount, maxExamples);
	for(var ri = 0; ri < showCount; ri++) {
		explanation.push("- " + analysis.ruleDescriptions[ri]);
		explanation.push("  `" + analysis.proposedRules[ri] + "`");
	}
	if(ruleCount > maxExamples) {
		explanation.push("- ... and " + (ruleCount - maxExamples) + " more rules");
		explanation.push("");
		explanation.push("See [[Import — Proposed Folder Structure]] for the full list. You can review it in the browser.");
	}
	explanation.push("");
	explanation.push("## Tiddler counts");
	explanation.push("- Content tiddlers: " + contentTiddlers.length);
	explanation.push("- System tiddlers: " + systemTiddlers.length);
	explanation.push("- Library plugins (added to tiddlywiki.info): " + libraryPlugins.length);
	explanation.push("- Custom plugins: " + customPlugins.length);
	explanation.push("- Ignored (boot/core): " + ignoredCount);
	var totalTags = Object.keys(analysis.tagCounts).length;
	var totalPrefixes = Object.keys(analysis.prefixCounts).length;
	if(totalTags > 0 || totalPrefixes > 0) {
		explanation.push("");
		explanation.push("## Summary");
		explanation.push("- " + totalTags + " unique tags found (" + analysis.proposedRules.filter(function(r) { return r.indexOf("[tag[") !== -1; }).length + " with " + MIN_GROUP_COUNT + "+ tiddlers → proposed as folders)");
		explanation.push("- " + totalPrefixes + " title prefixes found (" + analysis.proposedRules.filter(function(r) { return r.indexOf("[prefix[") !== -1; }).length + " with " + MIN_GROUP_COUNT + "+ tiddlers → proposed as folders)");
	}
	// Store analysis tiddler
	var analysisTiddler = new $tw.Tiddler({
		title: "$:/temp/mcp/html-import",
		type: "text/vnd.tiddlywiki",
		text: explanation.join("\n"),
		status: "pending",
		"source-file": filePath,
		"content-count": String(contentTiddlers.length),
		"system-count": String(systemTiddlers.length),
		"library-plugin-count": String(libraryPlugins.length),
		"custom-plugin-count": String(customPlugins.length),
		"proposed-filesystem-paths": analysis.proposedText
	});
	wiki.addTiddler(analysisTiddler);
	// Create a visible tiddler with the full proposed rules (browsable in the wiki)
	var fullRulesLines = [
		"! Proposed Folder Structure",
		"",
		"These rules will be used by `$:/config/FileSystemPaths` to organize your tiddlers into subdirectories.",
		"Each tiddler is tested against the rules in order — the first match determines the folder.",
		"",
		"!! Rules (" + ruleCount + ")",
		""
	];
	for(var fri = 0; fri < analysis.ruleDescriptions.length; fri++) {
		fullRulesLines.push("# " + analysis.ruleDescriptions[fri]);
		fullRulesLines.push("#* `" + analysis.proposedRules[fri] + "`");
	}
	fullRulesLines.push("");
	fullRulesLines.push("!! What to do");
	fullRulesLines.push("");
	fullRulesLines.push("# Review the rules above");
	fullRulesLines.push("# Edit [[$:/config/FileSystemPaths]] in the browser if you want to change anything");
	fullRulesLines.push("# Tell the AI assistant to proceed with extraction");
	fullRulesLines.push("");
	fullRulesLines.push("[[Full documentation|https://tiddlywiki.com/#Customising%20Tiddler%20File%20Naming]]");
	var now = $tw.utils.stringifyDate(new Date());
	wiki.addTiddler(new $tw.Tiddler({
		title: "Import — Proposed Folder Structure",
		text: fullRulesLines.join("\n"),
		tags: "Import",
		modified: now,
		created: now
	}));
	// Create $:/config/FileSystemPaths so user can edit it in the browser before extraction
	wiki.addTiddler(new $tw.Tiddler({
		title: "$:/config/FileSystemPaths",
		text: analysis.proposedText,
		modified: now,
		created: now
	}));
	// Set as default tiddler so it opens on startup in the browser
	wiki.addTiddler(new $tw.Tiddler({
		title: "$:/DefaultTiddlers",
		text: "[[Import — Proposed Folder Structure]]"
	}));
	// Log summary to stderr
	console.error("");
	console.error("html-import: Loaded " + filePath);
	console.error("  " + contentTiddlers.length + " content + " + systemTiddlers.length + " system tiddlers imported to memory");
	console.error("  " + libraryPlugins.length + " library plugins added to tiddlywiki.info");
	console.error("  " + analysis.proposedRules.length + " FileSystemPaths rules proposed");
	console.error("");
	console.error("  Tiddlers are in memory only — nothing written to disk yet.");
	console.error("");
	console.error("  Next steps:");
	console.error("    1. Connect an MCP client to this wiki (see below)");
	console.error("    2. Ask the AI: \"Check the tiddlywiki wiki info\"");
	console.error("    3. The AI will show the proposed folder structure for your review");
	console.error("    4. After you approve, the AI extracts .tid files to disk");
	console.error("");
	console.error("  Or browse the wiki at the URL shown below.");
	console.error("");
	console.error("  === Connect Claude Code ===");
	console.error("  claude mcp add --transport stdio tiddlywiki -- tiddlywiki " + wikiPath + " --mcp rw label=claude");
	console.error("");
	console.error("  === Connect Gemini CLI ===");
	console.error("  gemini mcp add --scope project tiddlywiki-mcp tiddlywiki " + wikiPath + " --mcp rw label=gemini");
	console.error("");
}

// --- MCP tool handler: extract to disk ---

function extractHandler(args) {
	var writeCheck = shared.checkWritable("extract_html_wiki");
	if(writeCheck) return writeCheck;
	var analysisTiddler = $tw.wiki.getTiddler("$:/temp/mcp/html-import");
	if(!analysisTiddler) {
		return shared.errorResult("No pending HTML import found. Use --mcp file=xxx.html to load a single-file wiki first.");
	}
	if(analysisTiddler.fields.status === "extracted") {
		return shared.errorResult("Tiddlers have already been extracted to disk.");
	}
	// Determine FileSystemPaths: args override > user-edited tiddler > proposed
	var fileSystemPathsText = args.fileSystemPaths
		|| $tw.wiki.getTiddlerText("$:/config/FileSystemPaths", "")
		|| analysisTiddler.fields["proposed-filesystem-paths"];
	if(!fileSystemPathsText) {
		return shared.errorResult("No FileSystemPaths rules available.");
	}
	// Update the FileSystemPaths config tiddler (in case args override was used)
	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: "$:/config/FileSystemPaths",
		text: fileSystemPathsText
	}));
	// Parse path filters
	var pathFilters = fileSystemPathsText.split("\n").filter(function(l) { return l.trim(); });
	var extFilters;
	if($tw.wiki.tiddlerExists("$:/config/FileSystemExtensions")) {
		extFilters = $tw.wiki.getTiddlerText("$:/config/FileSystemExtensions", "").split("\n");
	}
	var tiddlersDir = $tw.boot.wikiTiddlersPath;
	if(!tiddlersDir) {
		return shared.errorResult("No wiki tiddlers path available.");
	}
	// Get tiddlers to extract — same exclusions as $:/core/save/all
	var allTitles = $tw.wiki.filterTiddlers(
		"[all[tiddlers]!has[plugin-type]]" +
		" -[prefix[$:/state/popup/]]" +
		" -[prefix[$:/temp/]]" +
		" -[prefix[$:/HistoryList]]" +
		" -[[$:/boot/boot.css]]" +
		" -[[$:/boot/boot.js]]" +
		" -[[$:/boot/bootprefix.js]]" +
		" -[[$:/library/sjcl.js]]" +
		" -[is[system]type[application/javascript]library[yes]]" +
		" -[status[pending]plugin-type[import]]"
	);
	var checkPathAllowed = shared.getCheckPathAllowed();
	var filesWritten = 0;
	var errors = [];
	var directorySummary = {};
	for(var i = 0; i < allTitles.length; i++) {
		var title = allTitles[i];
		// Skip tiddlers that already have fileInfo (already on disk)
		if($tw.boot.files[title]) continue;
		var tiddler = $tw.wiki.getTiddler(title);
		if(!tiddler) continue;
		try {
			var fileInfo = $tw.utils.generateTiddlerFileInfo(tiddler, {
				directory: tiddlersDir,
				pathFilters: pathFilters,
				extFilters: extFilters,
				wiki: $tw.wiki,
				fileInfo: {}
			});
			var pathDenied = checkPathAllowed(fileInfo.filepath);
			if(pathDenied) {
				errors.push(title + ": path denied");
				continue;
			}
			$tw.utils.saveTiddlerToFileSync(tiddler, fileInfo);
			$tw.boot.files[title] = fileInfo;
			filesWritten++;
			// Track directory for summary
			var relPath = path.relative(tiddlersDir, fileInfo.filepath);
			var dir = path.dirname(relPath);
			directorySummary[dir] = (directorySummary[dir] || 0) + 1;
		} catch(e) {
			errors.push(title + ": " + e.message);
		}
	}
	// Update analysis tiddler status
	$tw.wiki.addTiddler(new $tw.Tiddler(analysisTiddler, {
		status: "extracted",
		"files-written": String(filesWritten)
	}));
	// Build result
	var lines = ["Extracted " + filesWritten + " tiddlers to " + tiddlersDir];
	lines.push("");
	var dirs = Object.keys(directorySummary).sort();
	for(var di = 0; di < dirs.length; di++) {
		lines.push("  " + (dirs[di] === "." ? "(root)" : dirs[di] + "/") + " — " + directorySummary[dirs[di]] + " files");
	}
	if(errors.length > 0) {
		lines.push("");
		lines.push(errors.length + " errors:");
		for(var ei = 0; ei < errors.length; ei++) {
			lines.push("  " + errors[ei]);
		}
	}
	var result = lines.join("\n");
	console.error("\nhtml-import: " + result + "\n");
	return shared.textResult(result);
}

module.exports = {
	initialize: initialize,
	"extract_html_wiki": extractHandler
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/inspect.js":{"title":"$:/core/modules/commands/inspect/handlers/inspect.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/inspect.js
type: application/javascript
module-type: library

MCP tool handlers for inspection and analysis operations.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

// Post-process inspect_pos DOM: replace verbose data-pos attributes
// with compact p="idx:lines" format. Returns title index header + innerHTML.
// Browser devtools keeps the full format; this compaction is MCP-only.
var SVG_TAGS = {"svg":1,"path":1,"g":1,"circle":1,"rect":1,"line":1,"polygon":1,
	"polyline":1,"ellipse":1,"use":1,"defs":1,"marker":1,"clipPath":1,"text":1,"tspan":1};

function compactPositions(container) {
	var titleMap = [];
	var titleIndex = {};
	var walk = function(node, inSvg) {
		if(!node.children) return;
		for(var i = 0; i < node.children.length; i++) {
			var child = node.children[i];
			if(!child.tag) continue;
			var isSvg = inSvg || SVG_TAGS[child.tag];
			// Strip devtools attributes (added by startup.js hooks if devtools plugin is loaded)
			child.removeAttribute("data-range");
			child.removeAttribute("data-ctx");
			child.removeAttribute("data-caller");
			var pos = child.getAttribute && child.getAttribute("data-pos");
			if(pos) {
				if(isSvg) {
					child.removeAttribute("data-pos");
				} else {
					var sepIdx = pos.indexOf(shared.SOURCE_POS_SEPARATOR);
					if(sepIdx !== -1) {
						var range = pos.slice(0, sepIdx);
						var title = pos.slice(sepIdx + shared.SOURCE_POS_SEPARATOR.length);
						var idx;
						if(titleIndex[title] !== undefined) {
							idx = titleIndex[title];
						} else {
							idx = titleMap.length;
							titleIndex[title] = idx;
							titleMap.push(title);
						}
						range = range.replace(/L/g, "");
						child.removeAttribute("data-pos");
						child.setAttribute("p", idx + ":" + range);
					} else {
						child.removeAttribute("data-pos");
					}
				}
			}
			walk(child, isSvg);
		}
	};
	walk(container, false);
	var header = "";
	if(titleMap.length > 0) {
		var parts = [];
		for(var i = 0; i < titleMap.length; i++) {
			parts.push(i + "=" + titleMap[i]);
		}
		header = "[" + parts.join(" ") + "]\n";
	}
	return header + container.innerHTML;
}

module.exports = {
	"inspect_tree": function(args) {
		if(args.text && args.text.length > shared.MAX_TEXT_LENGTH) {
			return shared.errorResult( "Text too long (" + args.text.length + " chars). Maximum: " + shared.MAX_TEXT_LENGTH );
		}
		try {
			var rendered = shared.parseAndRender(args.text, args.type, args.context);
			if(!rendered) {
				return shared.errorResult( "No parser for text" );
			}
			var widgetNode = rendered.widgetNode;
			var wExcludeSet = {};
			if(args.exclude) {
				for(var we = 0; we < args.exclude.length; we++) {
					wExcludeSet[args.exclude[we]] = true;
				}
			}
			var wIncludeSet = {};
			if(args.include) {
				for(var wi = 0; wi < args.include.length; wi++) {
					wIncludeSet[args.include[wi]] = true;
				}
			}
			var maxDepth = args.depth || 3;
			var maxChildren = 10;
			var typeCounts = {};
			var linkTargets = [];
			var countTypes = function(wn) {
				var type = wn.parseTreeNode.type;
				typeCounts[type] = (typeCounts[type] || 0) + 1;
				if(type === "link" && wn.attributes && wn.attributes.to) {
					var target = wn.getAttribute("to");
					if(target && linkTargets.indexOf(target) === -1) {
						linkTargets.push(target);
					}
				}
				if(wn.children) {
					$tw.utils.each(wn.children, countTypes);
				}
			};
			countTypes(widgetNode);
			var copyNode = function(wn, rn, depth) {
				var type = wn.parseTreeNode.type;
				rn.type = type;
				if(type === "element") {
					rn.tag = wn.parseTreeNode.tag;
				} else if(type === "text") {
					var txt = wn.parseTreeNode.text;
					rn.text = wIncludeSet.text ? txt : "s:" + txt.length;
				}
				if(wn.attributes && Object.keys(wn.attributes).length > 0) {
					rn.attributes = {};
					$tw.utils.each(wn.attributes, function(attr, attrName) {
						if(wExcludeSet[attrName]) return;
						rn.attributes[attrName] = wn.getAttribute(attrName);
					});
				}
				if(wn.children && wn.children.length > 0) {
					if(depth >= maxDepth) {
						rn.children = "{" + wn.children.length + " nodes}";
					} else {
						rn.children = [];
						var limit = Math.min(wn.children.length, maxChildren);
						for(var ci = 0; ci < limit; ci++) {
							var node = {};
							rn.children.push(node);
							copyNode(wn.children[ci], node, depth + 1);
						}
						if(wn.children.length > maxChildren) {
							rn.children.push("+" + (wn.children.length - maxChildren) + " more");
						}
					}
				}
			};
			var result = {};
			copyNode(widgetNode, result, 0);
			var summary = [];
			var sortedTypes = Object.keys(typeCounts).sort(function(a, b) { return typeCounts[b] - typeCounts[a]; });
			for(var si = 0; si < sortedTypes.length; si++) {
				summary.push(typeCounts[sortedTypes[si]] + " " + sortedTypes[si]);
			}
			var totalNodes = 0;
			for(var ti = 0; ti < sortedTypes.length; ti++) {
				totalNodes += typeCounts[sortedTypes[ti]];
			}
			var header = "Total: " + totalNodes + " nodes (full tree). Types: " + summary.join(", ") + "\n";
			if(linkTargets.length > 0) {
				header += "Links (" + linkTargets.length + "): " + linkTargets.join(", ") + "\n";
			}
			if(linkTargets.length > 0) {
				return shared.textResult( header );
			}
			header += "(showing depth=" + maxDepth + ")\n";
			return shared.textResult( header + JSON.stringify(result, null, $tw.config.preferences.jsonSpaces) );
		} catch(e) {
			return shared.errorResult( "inspect_tree error: " + e.message );
		}
	},

	"inspect_pos": function(args) {
		if(args.text && args.text.length > shared.MAX_TEXT_LENGTH) {
			return shared.errorResult( "Text too long (" + args.text.length + " chars). Maximum: " + shared.MAX_TEXT_LENGTH );
		}
		var inputType = args.type || "text/vnd.tiddlywiki";
		try {
			var parser = $tw.wiki.parseText(inputType, args.text, { parseAsInline: false });
			if(!parser) {
				return shared.errorResult( "No parser for type: " + inputType );
			}
			var importFilter = $tw.wiki.getTiddlerText("$:/core/config/GlobalImportFilter");
			var wrappedTree = {tree: [{
				type: "importvariables",
				attributes: {
					filter: { name: "filter", type: "string", value: importFilter }
				},
				isBlock: false,
				children: parser.tree
			}]};
			var widgetOptions = { document: $tw.fakeDocument };
			if(args.context) {
				widgetOptions.variables = { currentTiddler: args.context };
			}
			$tw.wiki.trackSourcePositions = true;
			var lineCache = {};
			var getLineOffsets = function(title) {
				if(lineCache[title]) return lineCache[title];
				var text = $tw.wiki.getTiddlerText(title, "");
				var offsets = [0];
				for(var ci = 0; ci < text.length; ci++) {
					if(text.charAt(ci) === "\n") offsets.push(ci + 1);
				}
				lineCache[title] = offsets;
				return offsets;
			};
			var charToLine = function(offsets, charPos) {
				var lo = 0, hi = offsets.length - 1;
				while(lo < hi) {
					var mid = (lo + hi + 1) >> 1;
					if(offsets[mid] <= charPos) lo = mid; else hi = mid - 1;
				}
				return lo + 1;
			};
			var posGetSourceInfo = function(widget) {
				var w = widget;
				while(w) {
					if(w.sourceContext !== undefined) {
						return { title: w.sourceContext, offset: w.sourceContextOffset || 0 };
					}
					w = w.parentWidget;
				}
				return null;
			};
			var headerCache = {};
			var getTidHeaderLines = function(title) {
				if(headerCache[title] !== undefined) return headerCache[title];
				var tiddler = $tw.wiki.getTiddler(title);
				if(!tiddler) { headerCache[title] = 0; return 0; }
				var exclude = {"text": true, "bag": true, "revision": true};
				var fieldCount = 0;
				for(var f in tiddler.fields) {
					if(!exclude[f]) fieldCount++;
				}
				headerCache[title] = fieldCount + 1;
				return headerCache[title];
			};
			var posBuildInfo = function(widget) {
				var ptn = widget.parseTreeNode;
				if(!ptn || ptn.start === undefined) return null;
				var info = posGetSourceInfo(widget);
				if(!info) return null;
				var offsets = getLineOffsets(info.title);
				var absStart = ptn.start + info.offset;
				var absEnd = (ptn.end || ptn.start) + info.offset;
				var startLine = charToLine(offsets, absStart);
				var endLine = charToLine(offsets, absEnd);
				var headerOffset = getTidHeaderLines(info.title);
				return shared.formatSourcePos(startLine + headerOffset, endLine + headerOffset, info.title);
			};
			var posHook = function(domNode, widget) {
				if($tw.wiki.trackSourcePositions) {
					var info = posBuildInfo(widget);
					if(info) domNode.setAttribute("data-pos", info);
				}
				return domNode;
			};
			$tw.hooks.addHook("th-dom-rendering-element", posHook);
			$tw.hooks.addHook("th-dom-rendering-link", posHook);
			$tw.hooks.addHook("th-dom-rendering-codeblock", posHook);
			var TranscludeWidget = require("$:/core/modules/widgets/transclude.js").transclude;
			var origExecute = TranscludeWidget.prototype.execute;
			var bodyOffsetCache = {};
			var findBodyOffset = function(title, bodyText) {
				var key = title + "\0" + bodyText.length;
				if(bodyOffsetCache[key] !== undefined) return bodyOffsetCache[key];
				var fullText = $tw.wiki.getTiddlerText(title, "");
				var idx = fullText.indexOf(bodyText);
				bodyOffsetCache[key] = idx >= 0 ? idx : 0;
				return bodyOffsetCache[key];
			};
			TranscludeWidget.prototype.execute = function() {
				origExecute.call(this);
				if($tw.wiki.trackSourcePositions) {
					if(this.transcludeVariable) {
						var varInfo = this.getVariableInfo(this.transcludeVariable);
						var srcVar = varInfo && varInfo.srcVariable;
						this.sourceContext = (srcVar && srcVar.sourceTitle) || this.transcludeVariable;
						this.sourceContextOffset = 0;
						if(srcVar && srcVar.sourceTitle && srcVar.value) {
							this.sourceContextOffset = findBodyOffset(srcVar.sourceTitle, srcVar.value);
						}
					} else if(this.transcludeTitle) {
						this.sourceContext = this.transcludeTitle;
						this.sourceContextOffset = 0;
					}
				}
			};
			try {
				var posWidget = $tw.wiki.makeWidget(wrappedTree, widgetOptions);
				posWidget.sourceContext = args.context || "(inline)";
				var posContainer = $tw.fakeDocument.createElement("div");
				posWidget.render(posContainer, null);
				return shared.textResult( compactPositions(posContainer) );
			} finally {
				$tw.wiki.trackSourcePositions = false;
				$tw.hooks.removeHook("th-dom-rendering-element", posHook);
				$tw.hooks.removeHook("th-dom-rendering-link", posHook);
				$tw.hooks.removeHook("th-dom-rendering-codeblock", posHook);
				TranscludeWidget.prototype.execute = origExecute;
			}
		} catch(e) {
			return shared.errorResult( "inspect_pos error: " + e.message );
		}
	},

	"inspect_tw": function(args) {
		var targetPath = (args.path || "").trim();
		var requestedDepth = args.depth || 1;
		var excludeSet = null;
		if(args.exclude && args.exclude.length > 0) {
			excludeSet = {};
			for(var e = 0; e < args.exclude.length; e++) {
				excludeSet[args.exclude[e]] = true;
			}
		}
		var target = $tw;
		var blockedSegments = {"__proto__": true, "constructor": true, "prototype": true};
		if(targetPath) {
			var segments = targetPath.split(".");
			for(var i = 0; i < segments.length; i++) {
				if(blockedSegments[segments[i]]) {
					return shared.errorResult( "Access to " + segments[i] + " is blocked for security" );
				}
				if(target === null || target === undefined) {
					return shared.errorResult( "$tw." + segments.slice(0, i).join(".") + " is " + String(target) );
				}
				if(typeof target !== "object" && typeof target !== "function") {
					return shared.errorResult( "$tw." + segments.slice(0, i).join(".") + " is " + typeof target );
				}
				target = target[segments[i]];
			}
		}
		var prefix = "$tw" + (targetPath ? "." + targetPath : "");
		if(target === null || target === undefined) {
			return shared.textResult( prefix + "=" + String(target) );
		}
		// Auto-resolve: path is an object (not function) + call provided + call[0] is a method name
		if(typeof target === "object" && target !== null && args.call && args.call.length > 0) {
			var methodName = args.call[0];
			if(typeof target[methodName] === "function") {
				var resolvedPath = targetPath + "." + methodName;
				var resolvedArgs = args.call.slice(1);
				return module.exports["inspect_tw"]({
					path: resolvedPath,
					call: resolvedArgs,
					depth: requestedDepth,
					exclude: args.exclude,
					fullSource: args.fullSource
				});
			} else {
				return shared.errorResult( prefix + " is not a function. '" + methodName + "' is " + typeof target[methodName] + " on this object. Did you mean path='" + targetPath + "." + methodName + "'?" );
			}
		}
		if(typeof target === "function") {
			if(args.call) {
				var safeCallFunctions = {
					"wiki.getTiddler": true,
					"wiki.getTiddlerText": true,
					"wiki.tiddlerExists": true,
					"wiki.isShadowTiddler": true,
					"wiki.getShadowSource": true,
					"wiki.filterTiddlers": true,
					"wiki.allTitles": true,
					"wiki.allShadowTitles": true,
					"wiki.getPluginInfo": true,
					"wiki.getPluginTypes": true,
					"wiki.getIndexer": true,
					"mcp.heartbeat": true,
					"httpServer.heartbeat": true
				};
				var isSafe = safeCallFunctions[targetPath] || targetPath.indexOf("utils.") === 0;
				if(!isSafe) {
					var safeList = Object.keys(safeCallFunctions).map(function(k) { return "$tw." + k; }).join(", ");
					return shared.errorResult( "call is only allowed on safe read-only functions: " + safeList + ", $tw.utils.*" );
				}
				var parent = $tw;
				if(targetPath) {
					var parentSegments = targetPath.split(".");
					parentSegments.pop();
					for(var pi = 0; pi < parentSegments.length; pi++) {
						parent = parent[parentSegments[pi]];
					}
				}
				try {
					target = target.apply(parent, args.call);
					prefix = prefix + "(" + args.call.map(function(a) { return JSON.stringify(a); }).join(",") + ")";
				} catch(callErr) {
					return shared.errorResult( prefix + " call error: " + callErr.message );
				}
			} else {
				var fnStr = Function.prototype.toString.call(target);
				var sigMatch = fnStr.match(/^(?:function\s*[^(]*)(\([^)]*\))/);
				var sig = sigMatch ? sigMatch[1] : "(" + (target.length || 0) + ")";
				var lines = [];
				lines.push("fn " + prefix + sig);
				lines = lines.concat(shared.formatFnSource(fnStr, "", !!args.fullSource));
				return shared.textResult( lines.join("\n") );
			}
		}
		if(typeof target !== "object") {
			return shared.textResult( prefix + "=" + String(target) );
		}
		var keys;
		try {
			keys = Object.keys(target);
		} catch(e) {
			return shared.errorResult( "Cannot enumerate " + prefix + ": " + e.message );
		}
		keys.sort();
		var availableDepth = shared.computeMaxDepth(target, 5);
		var MAX_RESULT_CHARS = 10000;
		var currentDepth = requestedDepth;
		var result, depthNote = "";
		while(currentDepth >= 0) {
			var lines = [];
			lines.push(prefix + " " + keys.length + "keys maxDepth=" + availableDepth);
			for(var k = 0; k < keys.length; k++) {
				if(excludeSet && excludeSet[keys[k]]) { continue; }
				try {
					lines = lines.concat(shared.inspectValue(target[keys[k]], keys[k], 0, currentDepth - 1, excludeSet));
				} catch(e) {
					lines.push(keys[k] + " !err");
				}
			}
			result = lines.join("\n");
			if(result.length <= MAX_RESULT_CHARS || currentDepth <= 0) {
				break;
			}
			currentDepth--;
		}
		if(currentDepth < requestedDepth) {
			depthNote = "\u26A0 depth reduced from " + requestedDepth + " to " + currentDepth + " (result exceeded " + MAX_RESULT_CHARS + " chars)\n";
		}
		return shared.textResult( depthNote + result );
	},

	"inspect_scope": function(args) {
		try {
			var textToRender;
			if(args.text) {
				textToRender = args.text;
			} else if(args.tiddler) {
				textToRender = $tw.wiki.getTiddlerText(args.tiddler, "");
				if(!textToRender) {
					return shared.errorResult( "Tiddler not found or empty: " + args.tiddler );
				}
			} else {
				return shared.errorResult( "Provide either 'tiddler' or 'text' parameter" );
			}
			var targetCharPos = args.charPos || 0;
			var contextTiddler = args.context || args.tiddler;
			var extraVars = null;
			var renderContext = args.renderContext || "isolated";
			if(renderContext === "viewtemplate" || renderContext === "root") {
				extraVars = {};
				extraVars["storyTiddler"] = contextTiddler || "";
				extraVars["tiddlerInfoState"] = "$:/state/popup/tiddler-info--" + (contextTiddler || "");
				extraVars["folded-state"] = "$:/state/folded/" + (contextTiddler || "");
			}
			if(renderContext === "root") {
				extraVars = extraVars || {};
				extraVars["tv-story-list"] = "$:/StoryList";
				extraVars["tv-history-list"] = "$:/HistoryList";
				extraVars["tv-config-toolbar-icons"] = $tw.wiki.getTiddlerText("$:/config/Toolbar/Icons", "yes");
				extraVars["tv-config-toolbar-text"] = $tw.wiki.getTiddlerText("$:/config/Toolbar/Text", "no");
				extraVars["tv-config-toolbar-class"] = $tw.wiki.getTiddlerText("$:/config/Toolbar/ButtonClass", "tc-btn-invisible");
				extraVars["tv-enable-drag-and-drop"] = $tw.wiki.getTiddlerText("$:/config/DragAndDrop/Enable", "yes");
				extraVars["tv-show-missing-links"] = $tw.wiki.getTiddlerText("$:/config/MissingLinks", "yes");
				extraVars["storyviewTitle"] = $tw.wiki.getTiddlerText("$:/view", "classic");
				extraVars["languageTitle"] = $tw.wiki.getTiddlerText("$:/language", "en-GB");
			}
			var rendered = shared.parseAndRender(textToRender, "text/vnd.tiddlywiki", contextTiddler, extraVars);
			if(!rendered) {
				return shared.errorResult( "No parser for text" );
			}
			var widgetNode = rendered.widgetNode;
			var matchCriteria = args.match || null;
			var widgetMatchesVars = function(wn) {
				if(!matchCriteria) return true;
				var keys = Object.keys(matchCriteria);
				for(var mi = 0; mi < keys.length; mi++) {
					var varName = keys[mi];
					var expected = matchCriteria[varName];
					var resolved = null;
					var pw = wn;
					while(pw) {
						if(pw.variables && pw.variables[varName]) {
							var v = pw.variables[varName];
							resolved = v.value !== undefined ? v.value : (v.text !== undefined ? v.text : null);
							break;
						}
						pw = pw.parentWidget;
					}
					if(resolved !== expected) return false;
				}
				return true;
			};
			var bestWidget = null;
			var bestDistance = Infinity;
			var walkTree = function(wn) {
				if(wn.parseTreeNode && wn.parseTreeNode.start !== undefined) {
					var dist = Math.abs(wn.parseTreeNode.start - targetCharPos);
					if(dist < bestDistance && widgetMatchesVars(wn)) {
						bestDistance = dist;
						bestWidget = wn;
					}
					if(wn.parseTreeNode.start === targetCharPos && widgetMatchesVars(wn)) {
						bestWidget = wn;
						bestDistance = 0;
					}
				}
				if(wn.children) {
					for(var ci = 0; ci < wn.children.length; ci++) {
						walkTree(wn.children[ci]);
					}
				}
			};
			walkTree(widgetNode);
			if(!bestWidget) {
				var matchInfo = matchCriteria ? " with match " + JSON.stringify(matchCriteria) : "";
				return shared.errorResult( "No widget found near char position " + targetCharPos + matchInfo );
			}
			var seen = {};
			var varList = [];
			var w = bestWidget;
			while(w) {
				if(w.variables) {
					var keys = Object.keys(w.variables);
					for(var vi = 0; vi < keys.length; vi++) {
						var vname = keys[vi];
						if(!seen[vname]) {
							seen[vname] = true;
							var v = w.variables[vname];
							varList.push({
								name: vname,
								value: v.value !== undefined ? v.value : (v.text !== undefined ? v.text : undefined),
								params: v.params || undefined,
								sourceTitle: v.sourceTitle || undefined,
								isMacro: v.isMacroDefinition || false,
								isProcedure: !!v.isProcedure || (v.configTrimWhiteSpace === true),
								isFunction: !!v.isFunctionDefinition,
								isWidget: !!v.isWidgetDefinition
							});
						}
					}
				}
				w = w.parentWidget;
			}
			var localVars = [];
			var importedVars = [];
			var varByName = {};
			for(var pi = 0; pi < varList.length; pi++) {
				varByName[varList[pi].name] = varList[pi];
				if(varList[pi].sourceTitle) {
					importedVars.push(varList[pi]);
				} else {
					localVars.push(varList[pi]);
				}
			}
			var usedNames = {};
			var collectVarRefs = function(node) {
				if(!node) return;
				if(node.attributes && node.attributes["$variable"]) {
					usedNames[node.attributes["$variable"].value] = true;
				}
				if(node.attributes) {
					var attrKeys = Object.keys(node.attributes);
					for(var ai = 0; ai < attrKeys.length; ai++) {
						var attr = node.attributes[attrKeys[ai]];
						if(attr.type === "macro" && attr.value && attr.value.attributes && attr.value.attributes["$variable"]) {
							usedNames[attr.value.attributes["$variable"].value] = true;
						} else if(attr.type === "indirect") {
							if(attr.textReference) usedNames[attr.textReference] = true;
						}
					}
				}
				if(node.children) {
					for(var ci = 0; ci < node.children.length; ci++) {
						collectVarRefs(node.children[ci]);
					}
				}
			};
			var parseTree = rendered.parser.tree;
			for(var ti = 0; ti < parseTree.length; ti++) {
				collectVarRefs(parseTree[ti]);
			}
			var followRefs = function(name, visited) {
				if(visited[name]) return;
				visited[name] = true;
				var entry = varByName[name];
				if(!entry) return;
				var body = entry.value || "";
				var varRefPattern = /<([^<>]+)>/g;
				var match;
				while((match = varRefPattern.exec(body)) !== null) {
					var refName = match[1];
					if(varByName[refName]) {
						usedNames[refName] = true;
						followRefs(refName, visited);
					}
				}
				var macroRefPattern = /<<([^\s>]+)/g;
				while((match = macroRefPattern.exec(body)) !== null) {
					var mRefName = match[1];
					if(varByName[mRefName]) {
						usedNames[mRefName] = true;
						followRefs(mRefName, visited);
					}
				}
			};
			var visited = {};
			var usedKeys = Object.keys(usedNames);
			for(var ui = 0; ui < usedKeys.length; ui++) {
				followRefs(usedKeys[ui], visited);
			}
			var usedImported = [];
			var unusedImported = [];
			for(var ii = 0; ii < importedVars.length; ii++) {
				if(usedNames[importedVars[ii].name]) {
					usedImported.push(importedVars[ii]);
				} else {
					unusedImported.push(importedVars[ii]);
				}
			}
			var filter = args.filter ? args.filter.toLowerCase() : null;
			if(filter) {
				localVars = localVars.filter(function(v) { return v.name.toLowerCase().indexOf(filter) !== -1; });
				usedImported = usedImported.filter(function(v) { return v.name.toLowerCase().indexOf(filter) !== -1; });
				unusedImported = unusedImported.filter(function(v) { return v.name.toLowerCase().indexOf(filter) !== -1; });
			}
			var showAll = !!args.all;
			var total = localVars.length + usedImported.length + unusedImported.length;
			var lines = [];
			var widgetType = bestWidget.parseTreeNode ? bestWidget.parseTreeNode.type : "unknown";
			lines.push("Scope at char " + targetCharPos + " (widget: " + widgetType + ", distance: " + bestDistance + ", " + total + " vars)");
			var formatEntry = function(entry) {
				var prefix;
				if(entry.isWidget) {
					prefix = "widget ";
				} else if(entry.isFunction) {
					prefix = "fn ";
				} else if(entry.isProcedure) {
					prefix = "proc ";
				} else if(entry.isMacro) {
					prefix = "macro ";
				} else if(entry.params) {
					prefix = "def ";
				} else {
					prefix = "var ";
				}
				var paramStr = entry.params ? "(" + entry.params.map(function(p) { return p.name + (p["default"] ? ":" + p["default"] : ""); }).join(", ") + ")" : "";
				var src = entry.sourceTitle ? " @" + entry.sourceTitle : "";
				if(!entry.params && entry.value !== undefined) {
					var val = String(entry.value);
					if(val.length > 70) val = val.substring(0, 70) + "~";
					return prefix + entry.name + " = " + val.replace(/\n/g, "\\n") + src;
				} else {
					return prefix + entry.name + paramStr + src;
				}
			};
			if(localVars.length > 0) {
				lines.push("");
				lines.push("— local scope");
				for(var li = 0; li < localVars.length; li++) {
					lines.push(formatEntry(localVars[li]));
				}
			}
			if(usedImported.length > 0) {
				lines.push("");
				lines.push("— used globals");
				for(var gi = 0; gi < usedImported.length; gi++) {
					lines.push(formatEntry(usedImported[gi]));
				}
			}
			if(showAll && unusedImported.length > 0) {
				lines.push("");
				lines.push("— other globals");
				for(var oi = 0; oi < unusedImported.length; oi++) {
					lines.push(formatEntry(unusedImported[oi]));
				}
			}
			if(!showAll && unusedImported.length > 0) {
				lines.push("");
				lines.push("+" + unusedImported.length + " globals (use all:true to see all, or filter to narrow)");
			}
			return shared.textResult( lines.join("\n") );
		} catch(e) {
			return shared.errorResult( "inspect_scope error: " + e.message );
		}
	}
};
